const initialValue = initialPortfolioValue;
const severity = geopoliticalEventSeverity;
const diversification = portfolioDiversificationScore;
const sectorExposure = vulnerableSectorExposure / 100;
const commoditySensitivity = commodityPriceSensitivityFactor;
const currencyExposure = foreignCurrencyExposurePercentage / 100;
const durationMonths = expectedEventDurationMonths;
const mitigationEffectiveness = riskMitigationEffectiveness / 100;

// --- Input Validation and Edge Cases ---
if (initialValue <= 0) {
    return { projectedPortfolioImpact: 0, percentageChange: 0, adjustedPortfolioValue: 0, geopoliticalRiskScore: 0 };
}

// --- Step 1: Calculate Base Geopolitical Impact Factor ---
// Normalizing severity to a 0.1-1.0 scale
const normalizedSeverity = Math.min(1.0, Math.max(0.1, severity / 10));

// Factors that amplify the impact
const diversificationAmplifier = (1 - diversification) * 0.7; // Lower diversification (e.g., 0.1 score -> 0.9 * 0.7 = 0.63 amplifier)
const sectorAmplifier = sectorExposure * 0.5; // Up to 0.5 for 100% exposure
const currencyAmplifier = currencyExposure * 0.4; // Up to 0.4 for 100% exposure

// Core impact factor combining base severity with portfolio sensitivities.
// The (1 + ...) ensures that even highly diversified/low exposure portfolios still feel some base severity.
const coreImpactFactor = normalizedSeverity * (1 + diversificationAmplifier + sectorAmplifier + currencyAmplifier);

// --- Step 2: Incorporate Commodity Price Sensitivity ---
// Sensitivity > 1 amplifies negative impact due to increased volatility and potential supply chain disruptions.
// Sensitivity < 1 is assumed to lessen the *additional* negative impact, but not create positive impact in this model.
const commodityRiskFactor = Math.max(0, commoditySensitivity - 1); // 0 if factor <= 1, positive if > 1.
const commoditySpecificImpact = initialValue * normalizedSeverity * commodityRiskFactor * 0.02; // Additional impact from commodity volatility

// --- Step 3: Adjust for Event Duration ---
// Longer duration generally means amplified negative impact. Use a power function for non-linear growth.
// Capped to prevent extreme amplification for very long durations.
const durationMultiplier = Math.min(2.0, (durationMonths > 1 ? Math.pow(durationMonths, 0.15) : 1)); // Cap at 2x amplification

// --- Step 4: Calculate Raw Financial Impact before Mitigation ---
// 0.08 is a general scaling factor to ensure the impact is within a realistic range for diversified portfolios.
const rawImpact = (initialValue * coreImpactFactor * 0.08 * durationMultiplier) + commoditySpecificImpact;

// --- Step 5: Apply Risk Mitigation Strategy Effectiveness ---
const finalImpact = rawImpact * (1 - mitigationEffectiveness);

// Ensure projected impact is always negative or zero for this risk analyzer.
const projectedImpact = -Math.abs(finalImpact);

// --- Step 6: Calculate Outputs ---
const percentageChange = (projectedImpact / initialValue) * 100;
const adjustedValue = initialValue + projectedImpact;

// --- Calculate Geopolitical Risk Score (0-100) ---
let geoRiskScoreRaw = 0;
geoRiskScoreRaw += (normalizedSeverity * 30); // 3 to 30 points
geoRiskScoreRaw += ((1 - diversification) * 20); // 0 to 18 points (for score 0.1)
geoRiskScoreRaw += (sectorExposure * 15); // 0 to 15 points
geoRiskScoreRaw += (commodityRiskFactor * 10); // 0 to 10 points (for factor 2.0)
geoRiskScoreRaw += (currencyExposure * 10); // 0 to 10 points
geoRiskScoreRaw += (durationMonths / 60) * 10; // ~0.16 to 10 points (for 1 to 60 months)

// Cap raw score and ensure a minimum floor (e.g., a low-risk event still carries some score)
geoRiskScoreRaw = Math.min(95, Math.max(5, geoRiskScoreRaw));

// Apply mitigation. Mitigation has a direct impact on the final risk score.
const finalGeoRiskScore = Math.max(0, geoRiskScoreRaw * (1 - mitigationEffectiveness));

return {
    projectedPortfolioImpact: projectedImpact,
    percentageChange: percentageChange,
    adjustedPortfolioValue: adjustedValue,
    geopoliticalRiskScore: Math.round(finalGeoRiskScore)
};
